     1→export const API_BASE = "http://localhost:3000/api";
     2→export const WS_URL = "ws://localhost:3000";
     3→
     4→export interface Session {
     5→  sessionId: string;
     6→  startedAt: string;
     7→  updatedAt: string;
     8→  cwd: string;
     9→  repoRoot: string | null;
    10→  repoName: string | null;
    11→  parentSessionId: string | null;
    12→  childSessionIds: string[];
    13→  gitUserName: string | null;
    14→  gitUserEmail: string | null;
    15→  prompt: string | null;
    16→  summary: string | null;
    17→  keywords: string[];
    18→  branch: string | null;
    19→  intent: string | null;
    20→  /** true when this session is currently indexed in a shadow branch */
    21→  isLive: boolean;
    22→}
    23→
    24→export interface Event {
    25→  id: number;
    26→  timestamp: string;
    27→  event: string;
    28→  sessionId: string;
    29→  blocked: boolean;
    30→  data: unknown;
    31→  summary: string | null;
    32→  keywords: string[];
    33→  /** Real LogEvent.id this synthetic event was derived from — set by logEventsToEvents. */
    34→  _sourceLogEventId?: number;
    35→  /** Additional LogEvent IDs for the same turn (e.g. separate thinking events). */
    36→  _extraSourceLogEventIds?: number[];
    37→  /** Original UUID from the JSONL log event this synthetic event was derived from. */
    38→  _sourceUuid?: string;
    39→}
    40→
    41→export interface InteractionOverview {
    42→  sessionId: string;
    43→  summary: string;
    44→  keywords: string[];
    45→  startedAt: string;
    46→  endedAt: string;
    47→}
    48→
    49→export interface RepoConfig {
    50→  name: string;
    51→  remote: string;
    52→  localPath: string;
    53→  dbPath: string;
    54→}
    55→
    56→export interface RepoStatus {
    57→  name: string;
    58→  localPath: string;
    59→  remote: string;
    60→  currentBranch: string | null;
    61→  latestCheckpointId: string | null;
    62→  gitUserName: string | null;
    63→  gitUserEmail: string | null;
    64→}
    65→
    66→export async function fetchRepoStatuses(): Promise<RepoStatus[]> {
    67→  const res = await fetch(`${API_BASE}/repos/status`);
    68→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    69→  return res.json() as Promise<RepoStatus[]>;
    70→}
    71→
    72→export async function fetchBranches(localPath: string): Promise<string[]> {
    73→  const res = await fetch(`${API_BASE}/branches?localPath=${encodeURIComponent(localPath)}`);
    74→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    75→  return res.json() as Promise<string[]>;
    76→}
    77→
    78→export async function fetchRepos(): Promise<RepoConfig[]> {
    79→  const res = await fetch(`${API_BASE}/repos`);
    80→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    81→  return res.json() as Promise<RepoConfig[]>;
    82→}
    83→
    84→export async function fetchCurrentRepo(): Promise<RepoConfig | null> {
    85→  const res = await fetch(`${API_BASE}/repos/current`);
    86→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    87→  return res.json() as Promise<RepoConfig | null>;
    88→}
    89→
    90→export async function addRepo(repo: { name: string; remote: string; localPath: string }): Promise<RepoConfig> {
    91→  const res = await fetch(`${API_BASE}/repos`, {
    92→    method: "POST",
    93→    headers: { "Content-Type": "application/json" },
    94→    body: JSON.stringify(repo),
    95→  });
    96→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    97→  return res.json() as Promise<RepoConfig>;
    98→}
    99→
   100→export async function deleteRepo(localPath: string): Promise<void> {
   101→  const res = await fetch(`${API_BASE}/repos`, {
   102→    method: "DELETE",
   103→    headers: { "Content-Type": "application/json" },
   104→    body: JSON.stringify({ localPath }),
   105→  });
   106→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
   107→}
   108→
   109→export async function fetchSessions(): Promise<Session[]> {
   110→  const res = await fetch(`${API_BASE}/sessions`);
   111→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
   112→  return res.json() as Promise<Session[]>;
   113→}
   114→
   115→export async function fetchSession(id: string): Promise<Session> {
   116→  const res = await fetch(`${API_BASE}/sessions/${encodeURIComponent(id)}`);
   117→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
   118→  return res.json() as Promise<Session>;
   119→}
   120→
   121→export async function fetchSessionOverview(id: string): Promise<InteractionOverview | null> {
   122→  const res = await fetch(`${API_BASE}/sessions/${encodeURIComponent(id)}/overview`);
   123→  if (res.status === 404) return null;
   124→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
   125→  return res.json() as Promise<InteractionOverview>;
   126→}
   127→
