   101→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
   102→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
   103→  delete process.env.CLAUDECODE;
   104→
   105→  const db = await getDb(dbPath);
   106→
   107→  // Ensure FTS table exists and is up-to-date on startup
   108→  await setupLogContentFts(db);
   109→  await syncLogContentFts(db);
   110→
   111→  const app = express();
   112→  app.use(cors());
   113→  app.use(express.json());
   114→
   115→  // Resolve git user and repo name from repo config once at startup
   116→  const gitUser  = getGitUser(repoDir);
   117→  const repoName = repoDir ? basename(repoDir) : null;
   118→
   119→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
   120→  app.get("/api/sessions", async (_req, res) => {
   121→    try {
   122→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
   123→      const allMetas = await db.checkpointSessionMetadata.findMany({
   124→        select: {
   125→          sessionId: true,
   126→          checkpointId: true,
   127→          branch: true,
   128→          summary: { select: { intent: true } },
   129→        },
   130→        orderBy: { createdAt: "asc" },
   131→      });
   132→      const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
   133→      for (const m of allMetas) {
   134→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
   135→      }
   136→
   137→      // Git user per checkpoint (from commit author stored at index time)
   138→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   139→      const cpUserRows = allCheckpointIds.length > 0
   140→        ? await db.checkpointMetadata.findMany({
   141→            where: { checkpointId: { in: allCheckpointIds } },
   142→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   143→          })
   144→        : [];
   145→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   146→
   147→      const shadows = await db.shadowSession.findMany();
   148→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   149→
   150→      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
   151→      if (allIds.length === 0) {
   152→        res.json([]);
   153→        return;
   154→      }
   155→
   156→      // Min/max LogEvent timestamps per session
   157→      const times = await db.logEvent.groupBy({
   158→        by: ["sessionId"],
   159→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   160→        _min: { timestamp: true },
   161→        _max: { timestamp: true },
   162→      });
   163→      const timeMap = new Map(
   164→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   165→      );
   166→
   167→      // First cwd per session
   168→      const cwdRows = await db.logEvent.findMany({
   169→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   170→        distinct: ["sessionId"],
   171→        orderBy: { id: "asc" },
   172→        select: { sessionId: true, cwd: true },
   173→      });
   174→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   175→
   176→      const result: SessionResponse[] = allIds.map((sessionId) => {
   177→        const cp     = cpMap.get(sessionId) ?? null;
   178→        const shadow = shadowMap.get(sessionId) ?? null;
   179→        const t      = timeMap.get(sessionId);
   180→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   181→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   182→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   183→        return {
   184→          sessionId,
   185→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   186→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   187→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   188→          repoRoot:        repoDir ?? null,
   189→          repoName:        repoName,
   190→          parentSessionId: null,
   191→          childSessionIds: [],
   192→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   193→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   194→          prompt:          shadow?.prompt ?? null,
   195→          summary:         null,
   196→          keywords:        [],
   197→          branch:          cp?.branch ?? shadow?.gitBranch ?? null,
   198→          intent:          cp?.intent ?? null,
   199→          isLive:          shadow !== null,
   200→        };
   201→      });
   202→
   203→      result.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
   204→      res.json(result);
   205→    } catch (err) {
   206→      res.status(500).json({ error: String(err) });
   207→    }
   208→  });
   209→
   210→  // GET /api/sessions/:id
   211→  app.get("/api/sessions/:id", async (req, res) => {
   212→    try {
   213→      const id = req.params.id;
   214→      const [latestMeta, shadow, firstEvent, lastEvent] = await Promise.all([
   215→        db.checkpointSessionMetadata.findFirst({
   216→          where: { sessionId: id },
   217→          select: { branch: true, checkpointId: true, summary: { select: { intent: true } } },
   218→          orderBy: { createdAt: "desc" },
   219→        }),
   220→        db.shadowSession.findUnique({ where: { sessionId: id } }),
   221→        db.logEvent.findFirst({
   222→          where: { sessionId: id },
   223→          orderBy: { id: "asc" },
   224→          select: { cwd: true, timestamp: true },
   225→        }),
   226→        db.logEvent.findFirst({
   227→          where: { sessionId: id, timestamp: { not: null } },
   228→          orderBy: { id: "desc" },
   229→          select: { timestamp: true },
   230→        }),
   231→      ]);
   232→      if (!latestMeta && !shadow) {
   233→        res.status(404).json({ error: "Session not found" });
   234→        return;
   235→      }
   236→      const cpMeta = latestMeta
   237→        ? await db.checkpointMetadata.findUnique({
   238→            where: { checkpointId: latestMeta.checkpointId },
   239→            select: { gitUserName: true, gitUserEmail: true },
   240→          })
   241→        : null;
   242→      const startedAt = firstEvent?.timestamp ?? shadow?.createdAt ?? null;
   243→      const updatedAt = lastEvent?.timestamp  ?? shadow?.createdAt ?? null;
   244→      res.json({
   245→        sessionId:       id,
   246→        startedAt:       startedAt?.toISOString() ?? new Date(0).toISOString(),
   247→        updatedAt:       updatedAt?.toISOString() ?? new Date(0).toISOString(),
