    36→  _extraSourceLogEventIds?: number[];
    37→  /** Original UUID from the JSONL log event this synthetic event was derived from. */
    38→  _sourceUuid?: string;
    39→}
    40→
    41→export interface InteractionOverview {
    42→  sessionId: string;
    43→  summary: string;
    44→  keywords: string[];
    45→  startedAt: string;
