   387→export function subscribeToUpdates(onUpdate: () => void): () => void {
   388→  let ws: WebSocket | null = null;
   389→  let timer: ReturnType<typeof setTimeout> | null = null;
   390→  let closed = false;
   391→  let delay = 1000;
   392→
   393→  function connect() {
   394→    if (closed) return;
   395→    ws = new WebSocket(WS_URL);
   396→
   397→    ws.onopen = () => {
   398→      delay = 1000; // reset backoff on successful connection
   399→    };
   400→
   401→    ws.onmessage = (e) => {
   402→      try {
   403→        const msg = JSON.parse(e.data as string) as { type: string };
   404→        if (msg.type === "sessions_updated") onUpdate();
   405→      } catch {
   406→        // ignore malformed messages
   407→      }
   408→    };
   409→
   410→    ws.onclose = () => {
   411→      if (closed) return;
   412→      timer = setTimeout(() => {
   413→        delay = Math.min(delay * 2, 30000);
   414→        connect();
   415→      }, delay);
   416→    };
   417→
   418→    ws.onerror = () => {
   419→      ws?.close();
   420→    };
   421→  }
   422→
   423→  connect();
   424→
   425→  return () => {
   426→    closed = true;
   427→    if (timer !== null) clearTimeout(timer);
   428→    ws?.close();
   429→  };
   430→}
