      if (!join) { res.status(404).end(); return; }
      const { stdout } = await exec(
        `git -C ${JSON.stringify(cpLocalPath)} diff-tree -p --no-commit-id -r ${join.gitOid}`,
      );
      res.set("Content-Type", "text/plain; charset=utf-8");
