                        ) : (
                          <Text size="sm" fw={500}>{repo.name}</Text>
                        )}
                      </Table.Td>
                      <Table.Td>
                        <Text size="sm" c="dimmed">{repo.gitUserName ?? repo.gitUserEmail ?? "—"}</Text>
                      </Table.Td>
                      <Table.Td>
                        <Text size="sm" ff="monospace" c={repo.currentBranch ? "teal" : "dimmed"}>
                          {repo.currentBranch ?? "—"}
                        </Text>
                      </Table.Td>
                    </Table.Tr>
                  ))}
                </Table.Tbody>
              </Table>
            </Table.ScrollContainer>
          </Box>
        )
      )}
    </Box>
  );
}

