                <Table.Tbody>
                  {sessions.map((item) => (
                    <SessionRow
                      key={item.sessionId}
                      session={item}
                      onPress={() =>
                        openSessionTab(
                          item.sessionId,
                          item.summary ?? item.intent ?? item.sessionId.slice(0, 8) + "…",
