                    {SESSION_COLUMNS.map(({ label, width }) => (
                      <Table.Th key={label} style={{ width, fontSize: 12, textTransform: "uppercase", letterSpacing: 0.5 }}>
                        {label}
                      </Table.Th>
                    ))}
                  </Table.Tr>
                </Table.Thead>
                <Table.Tbody>
                  {sessions.map((item) => (
                    <SessionRow
                      key={item.sessionId}
                      session={item}
                      onPress={() =>
                        openSessionTab(
                          item.sessionId,
                          item.summary ?? item.intent ?? item.sessionId.slice(0, 8) + "…",
                        )
                      }
                      onResume={(s) =>
                        openLauncherTab(
                          s.cwd,
                          `claude resume ${s.sessionId}`,
