    89→
    90→// ─── Parsing ──────────────────────────────────────────────────────────────────
    91→
    92→/**
    93→ * Parse a full.jsonl string into an array of event objects.
    94→ * Malformed lines are silently skipped.
    95→ */
    96→export function parseFullJsonl(content: string): FullJsonlEvent[] {
    97→  const out: FullJsonlEvent[] = [];
    98→  for (const line of content.split("\n")) {
    99→    const trimmed = line.trim();
   100→    if (!trimmed) continue;
   101→    try {
   102→      out.push(JSON.parse(trimmed) as FullJsonlEvent);
   103→    } catch {
   104→      // skip malformed line
   105→    }
   106→  }
   107→  return out;
   108→}
   109→
   110→/** Return the unique key for an event, preferring uuid then messageId. */
   111→function eventKey(e: FullJsonlEvent): string | null {
   112→  return e.uuid ?? e.messageId ?? null;
   113→}
   114→
   115→// ─── Git OID mapping helper ───────────────────────────────────────────────────
   116→
   117→async function saveGitOidMapping(
   118→  db: PrismaClient,
   119→  checkpointId: string,
   120→  branch: string | null | undefined,
   121→  repoPath: string,
   122→  existingMappings?: Map<string, string>,
   123→): Promise<void> {
   124→  if (!branch) return;
   125→  try {
   126→    const commit = await findCommitForCheckpoint(repoPath, branch, checkpointId);
   127→    if (!commit) return;
   128→    const existingOid = existingMappings?.get(checkpointId);
   129→    if (existingOid === commit.hash) return; // exact (checkpointId, gitOid) pair already recorded
   130→    // OID is new or changed (e.g. after rebase) — replace old entry if present
   131→    if (existingOid) {
   132→      await db.checkpointIdGitOidJoin.delete({ where: { gitOid: existingOid } }).catch(() => {});
   133→    }
   134→    await db.checkpointIdGitOidJoin.upsert({
   135→      where: { gitOid: commit.hash },
   136→      create: { gitOid: commit.hash, checkpointId },
   137→      update: { checkpointId },
   138→    });
   139→    await db.checkpointMetadata.updateMany({
   140→      where: { checkpointId },
   141→      data: { gitUserName: commit.authorName || null, gitUserEmail: commit.authorEmail || null },
   142→    });
   143→    existingMappings?.set(checkpointId, commit.hash);
   144→  } catch {
   145→    // non-fatal — git may not be available or branch may not exist
   146→  }
   147→}
   148→
   149→// ─── Single-checkpoint indexer ────────────────────────────────────────────────
   150→
   151→/**
   152→ * Index one checkpoint directory (the folder named by the last 10 hex chars,
   153→ * e.g. `<root>/0c/b6cf391c40`).
   154→ *
   155→ * @returns Number of new messages written (already-indexed events are skipped).
   156→ */
   157→
   158→// ─── V2 helpers ───────────────────────────────────────────────────────────────
   159→
   160→async function upsertFilePath(db: PrismaClient, path: string): Promise<number> {
   161→  const existing = await db.filePath.findUnique({ where: { path }, select: { id: true } });
   162→  if (existing) return existing.id;
   163→  const created = await db.filePath.create({ data: { path } });
   164→  return created.id;
   165→}
   166→
   167→async function createTokenUsage(db: PrismaClient, tu: Record<string, unknown>): Promise<number> {
