  user:            160,
  repo:            130,
  branch:          120,
  intent:          340,
  parentSessionId: 120,
  started:         110,
  updated:         110,
  actions:          56,
} as const;



function activityDot(updatedAt: string): { color: string; label: string } {
  const diff = Date.now() - new Date(updatedAt).getTime();
  if (diff < 2 * 60 * 1000)  return { color: "var(--mantine-color-green-6)", label: "Active" };
