   101→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
   102→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
   103→  delete process.env.CLAUDECODE;
   104→
   105→  const db = await getDb(dbPath);
   106→
   107→  // Ensure ArchivedSession table exists (can't use prisma db push due to FTS5 table conflicts)
   108→  await db.$executeRawUnsafe(
   109→    `CREATE TABLE IF NOT EXISTS "ArchivedSession" (sessionId TEXT PRIMARY KEY, archivedAt DATETIME NOT NULL DEFAULT (datetime('now')))`
   110→  );
   111→
   112→  // Ensure SessionParent table exists (parent-child session relationships from task checkpoints)
   113→  await db.$executeRawUnsafe(
   114→    `CREATE TABLE IF NOT EXISTS "SessionParent" (childSessionId TEXT PRIMARY KEY, parentSessionId TEXT NOT NULL, toolUseId TEXT)`
   115→  );
   116→
   117→  // Ensure FTS table exists and is up-to-date on startup
   118→  await setupLogContentFts(db);
   119→  await syncLogContentFts(db);
   120→
   121→  const app = express();
   122→  app.use(cors());
   123→  app.use(express.json());
   124→
   125→  // Resolve git user and repo name from repo config once at startup
   126→  const gitUser  = getGitUser(repoDir);
   127→  const repoName = repoDir ? basename(repoDir) : null;
   128→
   129→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
   130→  app.get("/api/sessions", async (_req, res) => {
   131→    try {
   132→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
   133→      const allMetas = await db.checkpointSessionMetadata.findMany({
   134→        select: {
   135→          sessionId: true,
   136→          checkpointId: true,
   137→          branch: true,
   138→          summary: { select: { intent: true } },
   139→        },
