  app.post("/api/sessions/:id/resume", (req, res) => {
    const sessionId = req.params.id;
    const { cwd } = req.body as { cwd?: string };
    try {
      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
